#!/usr/bin/env bash
# ⚠ EXPERIMENTAL — Codex multi-agent team overlay (WIP). Built on Codex's unstable
# collaboration_mode / spawn_agent v2 APIs (expect churn; pin a known-good version). No native git-worktree
# isolation; `codex exec` exits 0 even on failure (verify via git log + test re-run, never the exit code);
# --output-schema only on the gpt-5 family (coding roles report via a filesystem ledger); OFF by default.
# Full caveats + design: docs/codex/team-overlay.md.

set -euo pipefail

# subagent-stop.sh — Codex SubagentStop hook (generated by scaffold-generate; placeholder-only).
# Wired in config.toml under [[hooks.SubagentStop]] for host=codex + mode=team (see
# templates/config.codex.team.toml). Replaces the Claude team-event-log.sh's TaskCompleted branch.
#
# WHAT IT DOES — (1) appends ONE durable JSON line {ts,event:"stop",agent,task} to
#   .codex-team/$TEAM_LABEL/events.jsonl
# and (2) is the place "spawned but no ledger row" DRIFT is noticed: a coding child that crashed still
# exits 0 (codex exec) while writing NO row to the orchestrator's tasks.jsonl ledger. When an
# implementer stops leaving no ledger row referencing its task, this hook records a warn-only
# {event:"drift",reason:"spawned-no-ledger-row"} line. It does NOT enforce — the orchestrator's
# 3-strike circuit breaker (design doc §6) is the enforcement surface; this hook only surfaces the signal.
#
# WARN-ONLY / NEVER-FAIL — every fallible step is guarded; the script always exits 0. The drift check
# is scoped to implementer roles only (the orchestrator + read-only reviewers legitimately write no
# ledger row), so it raises no false positives for non-coding children.
#
# EXPERIMENTAL CAVEAT — Codex's SubagentStop payload shape is on the unstable v2 surface and is NOT yet
# pinned; the agent/task fields are read best-effort (stdin JSON, then env). Adapt to your Codex build.

PROJECT_DIR="${{{PROJECT_DIR_ENV}}:-$PWD}"   # {{PROJECT_DIR_ENV}} resolves to CODEX_PROJECT_DIR for codex
TEAM_LABEL="${TEAM_LABEL:-team}"             # ledger/event-log dir key (single-track v1: no <track> prefix)
TEAM_DIR="$PROJECT_DIR/.codex-team/$TEAM_LABEL"
EVENTS="$TEAM_DIR/events.jsonl"
LEDGER="$TEAM_DIR/tasks.jsonl"               # orchestrator-owned source of truth for coding roles

# Read the hook payload off stdin if present (a real hook gets JSON, not a tty).
payload=""
if [ ! -t 0 ]; then
  payload=$(cat 2>/dev/null || true)
fi

# get <jq-path> — best-effort extraction from the payload; always returns 0 (never trips set -e).
get() {
  command -v jq >/dev/null 2>&1 || return 0
  [ -n "$payload" ] || return 0
  printf '%s' "$payload" | jq -r "$1 // empty" 2>/dev/null || return 0
}

# Field names are best-effort guesses against the experimental v2 payload; env vars are the fallback.
agent=$(get '.agent // .role // .subagent_type // .agent_role')
[ -n "$agent" ] || agent="${CODEX_AGENT_ROLE:-${CODEX_SUBAGENT:-unknown}}"
task=$(get '.task // .task_path // .task_id // .thread')
[ -n "$task" ] || task="${CODEX_TASK_PATH:-${CODEX_TASK_ID:-}}"

ts=$(date -u +%Y-%m-%dT%H:%M:%SZ 2>/dev/null || echo unknown)
mkdir -p "$TEAM_DIR" 2>/dev/null || true

# emit <event> [reason] — append one JSON line to events.jsonl. Prefers jq; falls back to a
# hand-rolled, escaped JSON line so the log still records when jq is absent.
emit() {
  local ev="${1:-unknown}" reason="${2:-}"
  if command -v jq >/dev/null 2>&1; then
    jq -nc \
      --arg ts "$ts" --arg event "$ev" --arg agent "$agent" --arg task "$task" --arg reason "$reason" \
      '{ts:$ts, event:$event, agent:$agent, task:$task}
        + (if $reason != "" then {reason:$reason} else {} end)' \
      >> "$EVENTS" 2>/dev/null || true
  else
    local a="$agent" t="$task" r="$reason" extra=""
    a=${a//\\/\\\\}; a=${a//\"/\\\"}
    t=${t//\\/\\\\}; t=${t//\"/\\\"}
    r=${r//\\/\\\\}; r=${r//\"/\\\"}
    if [ -n "$r" ]; then extra=",\"reason\":\"$r\""; fi
    printf '{"ts":"%s","event":"%s","agent":"%s","task":"%s"%s}\n' "$ts" "$ev" "$a" "$t" "$extra" \
      >> "$EVENTS" 2>/dev/null || true
  fi
}

emit stop

# ── "spawned but no ledger row" drift detection (design doc §6 — the circuit-breaker signal) ───────
# Only implementer children are the source of truth via tasks.jsonl; reviewers/orchestrator write no
# per-slice row, so scope the check to implementer roles to avoid false positives. The ledger may
# reference a slice by its full canonical task path (/root/slice-P3.2) OR by its slice id (P3.2).
case "$agent" in
  *impl*)   # matches "implementer" and the "impl" nickname; reviewers/orchestrator are excluded
    if [ -n "$task" ] && [ -f "$LEDGER" ]; then
      slice="${task##*slice-}"          # /root/slice-P3.2 -> P3.2 ; otherwise the whole task string
      found=0
      if grep -qiF -e "$task" "$LEDGER" 2>/dev/null; then found=1; fi
      if [ "$found" -eq 0 ] && [ -n "$slice" ] && [ "$slice" != "$task" ]; then
        if grep -qiF -e "$slice" "$LEDGER" 2>/dev/null; then found=1; fi
      fi
      if [ "$found" -eq 0 ]; then
        # Warn-only signal: a codex-exec exit-0 no-op (child "succeeded" but did nothing). The
        # orchestrator independently verifies (git log + suite re-run) and ticks the circuit breaker.
        emit drift "spawned-no-ledger-row"
      fi
    fi
    ;;
esac

exit 0
